180:                 }
181:                 rpc_encode_decode!(enum $name { $($method),* });
182:             )*
183: 
184:             pub(super) enum Method {
185:                 $($name($name)),*
186:             }
187:             rpc_encode_decode!(enum Method { $($name(m)),* });
188:         }
